    def _deal_with_super_sub(self, string: str, style='plain') -> str:
        name, supers, subs = self._split_super_sub(string)

        # apply the style only to the name
        if style == 'bold':
            name = "\\mathbf{{{}}}".format(name)

        # glue all items together:
        if supers:
            name += "^{%s}" % " ".join(supers)
        if subs:
            name += "_{%s}" % " ".join(subs)

        return name

