    def _print_Manifold(self, manifold):
        name, supers, subs = self._split_super_sub(manifold.name.name)

        name = r'\text{%s}' % name
        if supers:
            name += "^{%s}" % " ".join(supers)
        if subs:
            name += "_{%s}" % " ".join(subs)

        return name

